# setup_project.ps1  -  run once from inside your RAG-BANK folder:
#     powershell -ExecutionPolicy Bypass -File .\setup_project.ps1
# Writes all project file contents (base64-encoded to stay intact).

$ErrorActionPreference = 'Stop'

$files = @{}
$files['README.md'] = ''
$files['requirements.txt'] = ''
$files['.gitignore'] = ''
$files['configs/recursive_hybrid.yaml'] = ''
$files['data/raw/neobank_faq.jsonl'] = ''
$files['data/eval/golden_set.jsonl'] = ''
$files['src/__init__.py'] = ''
$files['src/ingest.py'] = ''
$files['src/chunk.py'] = ''
$files['src/retrieve.py'] = ''

foreach ($rel in $files.Keys) {
    $path = Join-Path (Get-Location) $rel
    $dir = Split-Path $path -Parent
    if (-not (Test-Path $dir)) { New-Item -ItemType Directory -Force -Path $dir | Out-Null }
    $bytes = [System.Convert]::FromBase64String($files[$rel])
    [System.IO.File]::WriteAllBytes($path, $bytes)
    Write-Host "wrote $rel"
}

# create empty stub files so the tree is complete
foreach ($stub in 'src/index.py','src/generate.py','src/evaluate.py') {
    $p = Join-Path (Get-Location) $stub
    if (-not (Test-Path $p)) { New-Item -ItemType File -Force -Path $p | Out-Null }
}

Write-Host ''
Write-Host 'Done. All files written.' -ForegroundColor Green